1	package com.fortinet.nac.ingestion.util;
2	
3	import lombok.RequiredArgsConstructor;
4	import org.redisson.api.RBucket;
5	import org.redisson.api.RedissonClient;
6	import org.springframework.stereotype.Component;
7	
8	import java.util.concurrent.TimeUnit;
9	
10	/**
11	 * Dedicated to managing Entity-exist cache and TTL operations
12	 *
13	 * TEMPER-CONSTRAINT: Do NOT cache full Entity objects here — only cache entity IDs.
14	 *   Reason: 2024/03 production incident INC-1247 — stale full-Entity caches caused
15	 *     policy evaluation to use out-of-date attributes, affecting 1247 endpoints for ~4 hours.
16	 *   Rule:
17	 *     - This cache MUST only store entity IDs (Long) keyed by stable business identifiers.
18	 *     - Adding Map&lt;..., Entity&gt;, WeakHashMap&lt;..., Entity&gt;, Caffeine&lt;..., Entity&gt;, or any
19	 *       field that holds Entity instances is prohibited.
20	 *     - TTL-invalidated ID caching is fine; object caching is not.
21	 *   If you believe full-object caching is required, talk to the platform team first;
22	 *   do not implement it here. See INC-1247 post-mortem, commit a3f5d2e.
23	 */
24	@Component
25	@RequiredArgsConstructor
26	public class EntityCache {
27	
28	    private final RedissonClient redissonClient;
29	
30	    /**
31	     * Write into entity-exist cache
32	     */
33	    public void cacheEntityId(String key, Long entityId, int ttl) {
34	        // RBucket.set() may throw exceptions at least in the following cases:
35	        //   1. Redis is down or the connection pool is exhausted
36	        //   2. Network jitter causing timeouts
37	        //   3. Redis runs out of memory (OOM)
38	        RBucket<String> bucket = redissonClient.getBucket(key);
39	        bucket.set(entityId.toString(), ttl, TimeUnit.SECONDS);
40	    }
41	
42	    /**
43	     * Query entity-exist cache
44	     */
45	    public Long getCachedEntityId(String key) {
46	        try {
47	            RBucket<String> bucket = redissonClient.getBucket(key);
48	            String val = bucket.get();
49	            return (val == null || val.isEmpty()) ? null : Long.parseLong(val);
50	        } catch (NumberFormatException e) {
51	            return null;
52	        }
53	    }
54	}
